values
  ('lib.marketing.marketing_profile_created', 'marketing', 'marketing', 'quick_win', 'שיווק והפצה: הנכס חדש נכנס למערכת', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'זווית שיווק: הנכס נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'שיווק והפצה: הנכס חדש נכנס למערכת', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הנכס חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־10,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', 'שיווק והפצה: שיווק פרופיל נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (שיווק והפצה/שיווק פרופיל נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.marketing.marketing_score_low', 'marketing', 'marketing', 'high_priority', 'שיווק והפצה: שינוי ציון/ביצוע בהנכס', 'חל שינוי בציון/בביצועים של הנכס שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הנכס שמשנה תעדוף.', 'זווית שיווק: עודכן ציון או מדד ביצועים עבור הנכס (שיווק ציון נמוך). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'שיווק והפצה: שינוי ציון/ביצוע בהנכס', 'בדוק מה הוביל לשינוי הציון בהנכס (שיווק ציון נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהנכס (שיווק ציון נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הנכס השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־10,000 ₪ בעסקה ממוצעת.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'שיווק והפצה: שיווק ציון נמוך. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (שיווק והפצה/שיווק ציון נמוך) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.marketing.marketing_opportunity_detected', 'marketing', 'marketing', 'revenue_opportunity', 'שיווק והפצה: הזדמנות שכדאי לממש', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זווית שיווק: זוהתה הזדמנות בשיווק והפצה (שיווק הזדמנות זוהה). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'שיווק והפצה: הזדמנות שכדאי לממש', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בשיווק והפצה ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־10,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'שיווק והפצה: שיווק הזדמנות זוהה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (שיווק והפצה/שיווק הזדמנות זוהה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
