  ('lib.marketing.distribution_should_update_seller_portal', 'marketing', 'marketing', 'follow_up_required', 'שיווק והפצה: הנכס זקוק לעדכון/קידום', 'הנכס זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'הנכס זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'זווית שיווק: הנכס הגיע לנקודה שמחייבת עדכון או קידום שלב (הפצה עדכון מוכר פורטל). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'שיווק והפצה: הנכס זקוק לעדכון/קידום', 'בצע את העדכון/הקידום הנדרש להנכס (הפצה עדכון מוכר פורטל), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש להנכס (הפצה עדכון מוכר פורטל), וודא שהשלב הבא ברור ומתואם.', 'הנכס ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־10,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'הנכס מעודכן, מסונכרן וממשיך ברצף תקין.', 'שיווק והפצה: הפצה עדכון מוכר פורטל. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (שיווק והפצה/הפצה עדכון מוכר פורטל) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.marketing.distribution_should_create_report', 'marketing', 'marketing', 'quick_win', 'שיווק והפצה: הנכס בשל לקבלת ערך ממוקד', 'הגיע הזמן לספק להנכס ערך ממוקד ומותאם.', 'הגיע הזמן לספק להנכס ערך ממוקד ומותאם.', 'זווית שיווק: הנכס בשל לקבלת תוצר ערך מותאם (הפצה יצירת דוח). אספקת תובנה או חבילה רלוונטית בזמן הנכון מחזקת אמון ומקדמת החלטה. מומלץ להכין את התוצר ולהציגו באופן אישי.', 'שיווק והפצה: הנכס בשל לקבלת ערך ממוקד', 'הכן להנכס את התוצר המתאים (הפצה יצירת דוח) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הכן להנכס את התוצר המתאים (הפצה יצירת דוח) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הנכס ראוי לאספקת ערך ממוקד. ודא שהתוצר הוכן ונמסר באיכות גבוהה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־10,000 ₪ בעסקה ממוצעת.', 'אספקת ערך בעיתוי הנכון מחזקת אמון ומקצרת את מסלול ההחלטה.', 'הנכס מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'שיווק והפצה: הפצה יצירת דוח. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מקבל ערך מותאם שמקדם אותו לשלב הבא.', null, null, null, 'אוטומציה (שיווק והפצה/הפצה יצירת דוח) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.marketing.property_with_high_demand_needs_promotion', 'marketing', 'marketing', 'high_priority', 'שיווק והפצה: הנכס בכוונה גבוהה — חלון הזדמנות (וריאנט 3)', 'הנכס מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הנכס מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'זווית שיווק: הנכס מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (נכס עם גבוה ביקוש זקוק קידום). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'שיווק והפצה: הנכס בכוונה גבוהה — חלון הזדמנות (וריאנט 3)', 'הנכס חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הנכס חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הנכס בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־10,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הנכס מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שיווק והפצה: נכס עם גבוה ביקוש זקוק קידום. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מקודם להחלטה תוך מיצוי חלון ההזדמנות.', null, null, null, 'אוטומציה (שיווק והפצה/נכס עם גבוה ביקוש זקוק קידום) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.marketing.property_stale_needs_marketing_boost', 'marketing', 'marketing', 'follow_up_required', 'שיווק והפצה: פער בטיפול בהנכס', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זווית שיווק: הנכס מציג פער (נכס מיושן זקוק שיווק חיזוק) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'שיווק והפצה: פער בטיפול בהנכס', 'השלם את החסר בהנכס (נכס מיושן זקוק שיווק חיזוק) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהנכס (נכס מיושן זקוק שיווק חיזוק) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהנכס. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־10,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', 'שיווק והפצה: נכס מיושן זקוק שיווק חיזוק. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (שיווק והפצה/נכס מיושן זקוק שיווק חיזוק) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
